A. 愤怒的牛 题目连接：Reach-Top
考虑二分两只牛之间的最小距离，然后用贪心放置牛的位置。
#include &lt;bits/stdc++.h&gt; using namespace std; const int N = 1e5 + 5; int n, m; int a[N]; bool check(int len) { int cnt = 1, last = a[1]; for (int i = 2; i &lt;= n; i++) { if (a[i] - last &gt;= len) { cnt++; last = a[i]; } } return cnt &gt;= m; } int main() { scanf(&#34;%d%d&#34;, &amp;n, &amp;m); for (int i = 1; i &lt;= n; i++) { scanf(&#34;%d&#34;, &amp;a[i]); } sort(a + 1, a + 1 + n); int low = 0, high = 1e9, ans = 1e9; while (low &lt;= high) { int mid = (low + high) / 2; if (check(mid)) { ans = mid; low = mid + 1; } else { high = mid - 1; } } printf(&#34;%d\n&#34;, ans); } B. 最好的牛围栏 题目连接：Reach-Top
考虑二分平均数，将所有数都减去该平均数，那么限制条件就变成了：
$$ \sum_{k=l}^{r}(a_i-ave)\geq 0 $$
用前缀和优化后就可以发现我们只关心前缀和的前缀最小值，可以用 $O(n)$ 的时间完成 check。
#include &lt;bits/stdc++.h&gt; using namespace std; const int N = 1e5 + 5; const double eps = 1e-6; int n, m; int a[N]; double sum[N]; bool check(double k) { sum[0] = 0; for (int i = 1; i &lt;= n; i++) { sum[i] = a[i] - k; sum[i] += sum[i - 1]; } double fmin = 1e9; for (int i = 1; i &lt;= n; i++) { if (i &gt;= m) { fmin = min(fmin, sum[i - m]); } if (sum[i] - fmin &gt;= 0) { return true; } } return false; } int main() { std::ios::sync_with_stdio(false); std::cout &lt;&lt; std::fixed &lt;&lt; setprecision(5); scanf(&#34;%d%d&#34;, &amp;n, &amp;m); for (int i = 1; i &lt;= n; i++) { scanf(&#34;%d&#34;, &amp;a[i]); } double ans = 0; for (double lo = 0, hi = 2e3; lo + eps &lt; hi; ) { double mid = (lo + hi) / 2; if (check(mid)) { lo = mid; ans = mid; } else { hi = mid; } } printf(&#34;%d\n&#34;, int(ans * 1000 + 0.5)); }

